import{_ as t}from"./nuxt-img.21f72a2d.js";import{k as n,l as i,R as o,S as e,U as s,V as r,o as c}from"./entry.47fb1a8f.js";const d={},m={class:"articles-tecnico-container"},u=e("h1",{class:"text-center text-5xl"},"HashSet.",-1),l=e("h3",null,"Serie - visão geral sobre estrutura de dados Java.",-1),h={class:"pt-4"},p=e("h3",null,"Como funciona?",-1),_=e("p",null,[s("  É uma estrutura de dados bem rápida. É uma tabela de hash, onde temos sim de certa forma um "),e("code",null,"<K, V>"),s(" (chave e valor), porém nós não lidamos com chave em HashSet (para isso use HashMap), a chave é insignificante (não trabalhamos e nem podemos lidar diretamente com elas), usada apenas para encontrar os elementos na tabela, e também para garantir que não tenhamos elementos duplicados:")],-1),v=e("p",null,"  A visualização geral é essa:",-1),f=r("<p>  Se você prestou atenção, deve ter percebido que os elementos adicionados ao <code>HashSet</code> não ficaram na mesma ordem que foram inseridos. Isso acontece porque o <code>HashSet</code> não mantém nenhuma ordem, nem mesmo a ordem de inserção. A forma como os elementos são ordenados varia de acordo com a implementação da JVM e de outros fatores. Além disso, é importante mencionar a função hash utilizada, que é uma função de hash padrão da classe <code>Object</code>. O número total de hashes possíveis é de 32 bits (em algumas implementações pode chegar a 64 bits), o que é relativamente pouco, e isso pode levar a <b>colisões entre os elementos do <code>HashSet</code></b>.</p><h3>E se houver colisões?</h3><p>  Se o hash é usado como próprio &quot;identificador&quot; dos elementos para evitar duplicação, o que acontece se houver dois elementos diferentes que geram o mesmo hash?</p><p>  Bem, o algoritmo de hash usado por <code>HashSet</code> é chamado de <b>hashing by chaining</b>, sua implementação não é importante aqui, mas ele funciona como uma tabela de hash e as <b>colisões são resolvidas usando listas encadeadas</b>. Ficou meio confuso eu sei, mas na visualização que já veremos vai dar para entender facilmente.</p><p>  Vamos usar exemplo de colisões com duas String, as String&#39;s &quot;FB&quot; e &quot;Ea&quot; geram o mesmo hash 2236. Isso aconteçe pois o hashCode() do Java usa uma função polinomial que produz um número finito de valores hash, por isso a colisão. Veremos agora então uma visualização de como funciona essa lista encadeada em caso de colisões (&quot;FB&quot; e &quot;Ea&quot;):</p>",5),g=e("p",null,[e("b",null,"Em resumo é uma estrutura para quando não quer elementos duplicados e não depende de ordenação, em caso de colisões como visto, se for fazer pesquisa nela vai jogar para um lista ligada vai verificar o primeiro elemento, se não for passa para o próximo e assim por diante.")],-1);function q(b,S){const a=t;return c(),i("main",m,[u,l,o(a,{src:"/static/images/linha-branca.png",alt:"Linha Branca"}),e("article",h,[p,_,v,o(a,{src:"/static/images/articles/estrutura-de-dados-java/hash-set.png",alt:"HashSet Java"}),f,o(a,{src:"/static/images/articles/estrutura-de-dados-java/hash-set-colisao.png",alt:"Colisão HashSet Java"}),g])])}const V=n(d,[["render",q]]);export{V as default};
